import {createSlice} from '@reduxjs/toolkit';
import error from 'console';
export const testSlice = createSlice({
    name: 'test',
    initialState: {
        items: 'Enterprise Semester' as string,
        loading: false,
        error: null as string | null,
    },
    reducers: { }
});
export const {} = testSlice.actions;
